// Step Builder: compile-time enforcement of required fields
public class PizzaBuilder {
    public interface SizeStep  { ToppingsStep size(String size); }
    public interface ToppingsStep { BuildStep toppings(String... t); }
    public interface BuildStep { Pizza build(); }

    public static SizeStep newBuilder() { return new Steps(); }

    private static class Steps implements SizeStep, ToppingsStep, BuildStep {
        private String size;
        private String[] toppings;

        public ToppingsStep size(String s) { this.size = s; return this; }
        public BuildStep toppings(String... t) { this.toppings = t; return this; }
        public Pizza build() {
            if (size == null) throw new IllegalStateException();
            return new Pizza(size, toppings);
        }
    }
}

