public class VideoConverterFacade {
    private VideoDecoder vd = new VideoDecoder();
    private AudioDecoder ad = new AudioDecoder();
    private VideoEncoder ve = new VideoEncoder();
    private AudioMixer   am = new AudioMixer();
    private FileWriter   fw = new FileWriter();

