        connect();
        List<Record> records   = extractData();        // abstract
        List<Record> transformed = transform(records); // hook
        loadData(transformed);                          // abstract
        disconnect();
    }

    protected abstract List<Record> extractData();
    protected abstract void loadData(List<Record> records);

    // Hook — default no-op; subclass may override
    protected List<Record> transform(List<Record> records) { return records; }

