public abstract class OrderProcessor {
    public final void process(Order order) { // template method
        validate(order);
        if (requiresApproval(order)) { // hook with meaningful default
            sendForApproval(order); return;
        }
        beforeProcess(order);  // no-op hook
        doProcess(order);      // abstract
        afterProcess(order);   // no-op hook
    }

    protected abstract void doProcess(Order order);

    // Hooks with defaults — optional override
    protected boolean requiresApproval(Order o) { return o.getTotal() > 10_000; }
    protected void beforeProcess(Order o) {}
    protected void afterProcess(Order o)  {}

    private void validate(Order o)        { /* always runs */ }
    private void sendForApproval(Order o) { /* always same logic */ }
}

