public abstract class RequestHandler {
    protected RequestHandler next;

    public RequestHandler setNext(RequestHandler next) {
        this.next = next; return next;
    }

    public abstract void handle(HttpRequest req, HttpResponse res);

    protected void passToNext(HttpRequest req, HttpResponse res) {
        if (next != null) next.handle(req, res);
    }
}

public class AuthHandler extends RequestHandler {
    public void handle(HttpRequest req, HttpResponse res) {
        if (!req.hasHeader("Authorization")) { res.setStatus(401); return; }
        passToNext(req, res); // only if authenticated
    }
}

public class LoggingHandler extends RequestHandler {
    public void handle(HttpRequest req, HttpResponse res) {
        System.out.println("Request: " + req.getPath());
        passToNext(req, res); // always passes (pipeline style)
        System.out.println("Response: " + res.getStatus());
    }
}

