// Servlet Filter — Chain of Responsibility as pipeline
@WebFilter("/*")
public class JwtAuthFilter implements Filter {
    @Override
    public void doFilter(ServletRequest req, ServletResponse res,
                         FilterChain chain) throws IOException, ServletException {
        HttpServletRequest  httpReq = (HttpServletRequest)  req;
        HttpServletResponse httpRes = (HttpServletResponse) res;

        String token = httpReq.getHeader("Authorization");
        if (token == null || !jwtService.validate(token)) {
            httpRes.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            return; // STOP the chain
        }

        SecurityContext.setUser(jwtService.getUser(token));
        chain.doFilter(req, res); // pass to next
        SecurityContext.clear();  // post-processing
    }
}

