// Chain of Responsibility: handler may STOP the chain
public class PermissionHandler extends RequestHandler {
    public void handle(Request req) {
        if (!hasPermission(req.getUser(), req.getResource())) {
            throw new AccessDeniedException(); // STOP
        }
        passToNext(req); // only if permitted — subsequent handlers skipped if denied
    }
}

public interface OrderState {
