        System.out.println("Payment received");
        ctx.setState(new PaidState()); // TRANSITION
    }
    public void ship(OrderContext ctx) { throw new IllegalStateException("Not paid"); }
    public void deliver(OrderContext ctx) { throw new IllegalStateException("Not paid"); }
}

