// Registry-based factory — open for extension at runtime
public class NotificationFactory {
    private static final Map<String, Supplier<Notification>> registry =
        new ConcurrentHashMap<>();

    // Register at startup or via plugin scan
    static {
        registry.put("email", EmailNotification::new);
        registry.put("sms",   SMSNotification::new);
        registry.put("push",  PushNotification::new);
    }

    public static void register(String type, Supplier<Notification> supplier) {
        registry.put(type, supplier); // add new type without modifying class
    }

    public static Notification create(String type) {
        Supplier<Notification> supplier = registry.get(type);
        if (supplier == null) throw new IllegalArgumentException("Unknown: " + type);
        return supplier.get();
    }
}

